function findIntegers(): string
{
    $result = array();
    for ($a = 1; $a <= 29; $a++) {
        for ($b = $a + 1; $b <= 29; $b++) {
            $sum = $a + $b;
            if (in_array($sum, array(10, 18, 19, 20, 21, 29))) {
                if ($sum == 10) {
                    $result[] = $a;
                    $result[] = 10 - $a;
                } elseif ($sum == 18) {
