                } elseif ($sum == 20) {
                    $result[] = $a;
                    $result[] = 20 - $a;
                } elseif ($sum == 21) {
                    $result[] = $a;
                    $result[] = 21 - $a;
                } else {
                    $result[] = $a;
                    $result[] = $sum - $a;
                }
            }
        }
    }
    sort($result);
    return implode(', ', $result);
}
