def is_multiply_prime(a):
    def is_prime(n):
        if n < 2:
            return False
        for i in range(2, int(n**0.5) + 1):
            if n % i == 0:
                return False
        return True

    count = 0
    i = 2
    while a > 1:
        if is_prime(i):
            if a % i == 0:
                a //= i
                count += 1
            else:
                a -= 1
        i += 1
    return count == 3
```

