    for i in range(2, n, 2):
        remaining = n - i
        if remaining % 2 == 0:
            if remaining > 2:
                for j in range(2, remaining//2 + 1, 2):
                    if j + remaining - j > 2:
                        for k in range(2, (remaining-j)//2 + 1, 2):
                            if k + j + remaining - j - k > 2:
