def encode_cyclic(s: str) -> str:
    result = ""
    for char in s:
        if char.isupper():
            result += chr((ord(char) - 65 + 1) % 26 + 65)
        else:
            result += chr((ord(char) - 97 + 1) % 26 + 97)
    return result

