def decode_cyclic(s: str) -> str:
    """
    Decodes a string encoded with encode_cyclic function.
    """
    decoded = []
    for c in s:
        if c == 'x':
            decoded.append(chr(int(decoded.pop()[:-1]) ^ ord('x')))
        else:
            decoded.append(c)
    return ''.join(reversed(decoded))
```
