    """
    decoded = []
    i = 0
    while i < len(s):
        if s[i] == 'x':
            i += 1
            if i < len(s) and s[i] == 'x':
                decoded.append(s[i-1])
                i += 1
            else:
                decoded.append(s[i-1])
        else:
            decoded.append(s[i])
        i += 1
    return ''.join(decoded)

