def strongest_extension(class_name, extensions):
    def calculate_strength(extension):
        return (extension.upper().count('-') - extension.lower().count('-')) / 1.0

    strongest = max(extensions, key=calculate_strength)
    return f"{class_name}.{strongest}"

def strongest_extension(class_name, extensions):
    strongest = None
    strongest_strength = float('-inf')

    for extension in extensions:
        sm = sum(c.islower() for c in extension)
        cap = sum(c.isupper() for c in extension)
        strength = cap - sm
        if strength > strongest_strength:
            strongest_strength = strength
            strongest = extension
        elif strength == strongest_strength:
            strongest = extension

    return f"{class_name}.{strongest}"

def Strongest_Extension(class_name, extensions):
    strongest_extension = max(extensions, key=lambda x: sum(1 for c in x if c.isupper) - sum(1 for c in x if c.islower))
    return f"{class_name}.{strongest_extension}"

